    for param in self.params:
        if not isinstance(param, Option) or not param._dynamic_default:
            continue

        if ctx.get_parameter_source(param.name) != ParameterSource.DEFAULT:  # type: ignore[arg-type]
            continue

        resolved: t.Any | None = None

        for source_opt, mapping in param._dynamic_default.items():
            source_value = None

            for other in self.params:
                if source_opt in other.opts or source_opt in other.secondary_opts:
                    source_value = ctx.params.get(other.name)  # type: ignore[arg-type]
